import 'dart:io';
import 'package:flutter/material.dart';
class ChatInputBar extends StatefulWidget{final bool isSending; final File? selectedImage; final VoidCallback onPickImage,onClearImage; final ValueChanged<String> onSendText,onSendImage; const ChatInputBar({super.key,this.isSending=false,this.selectedImage,required this.onPickImage,required this.onClearImage,required this.onSendText,required this.onSendImage}); @override State<ChatInputBar> createState()=>_ChatInputBarState();}
class _ChatInputBarState extends State<ChatInputBar>{final _controller=TextEditingController(); @override void dispose(){_controller.dispose();super.dispose();} void _submit(){final text=_controller.text.trim(); if(widget.selectedImage!=null){widget.onSendImage(text);_controller.clear();return;} if(text.isEmpty)return; widget.onSendText(text);_controller.clear();} @override Widget build(BuildContext context)=>SafeArea(top:false,child:Material(elevation:8,color:Theme.of(context).colorScheme.surface,child:Padding(padding:const EdgeInsets.fromLTRB(8,8,8,10),child:Column(mainAxisSize:MainAxisSize.min,children:[if(widget.selectedImage!=null)...[_SelectedImagePreview(file:widget.selectedImage!,onRemove:widget.onClearImage),const SizedBox(height:8)],Row(children:[IconButton(onPressed:widget.isSending?null:widget.onPickImage,icon:const Icon(Icons.image_outlined)),Expanded(child:TextField(controller:_controller,enabled:!widget.isSending,minLines:1,maxLines:4,textInputAction:TextInputAction.send,decoration:const InputDecoration(hintText:'Message...',border:OutlineInputBorder(),isDense:true),onSubmitted:(_)=>_submit())),const SizedBox(width:8),IconButton.filled(onPressed:widget.isSending?null:_submit,icon:widget.isSending?const SizedBox(width:18,height:18,child:CircularProgressIndicator(strokeWidth:2)):const Icon(Icons.send))])]))));}
class _SelectedImagePreview extends StatelessWidget{final File file; final VoidCallback onRemove; const _SelectedImagePreview({required this.file,required this.onRemove}); @override Widget build(BuildContext context)=>Align(alignment:Alignment.centerLeft,child:Stack(children:[ClipRRect(borderRadius:BorderRadius.circular(12),child:Image.file(file,width:96,height:96,fit:BoxFit.cover)),Positioned(top:4,right:4,child:Material(color:Colors.black54,shape:const CircleBorder(),child:InkWell(customBorder:const CircleBorder(),onTap:onRemove,child:const Padding(padding:EdgeInsets.all(4),child:Icon(Icons.close,color:Colors.white,size:16)))))]));}
